    theta_M = math.asin(math.sqrt(beta))
    G = np.array([[0.0, 1.0], [-1.0, 0.0]])
    S0 = _expm(theta_M * G).real
    # (b) sombra: reescalar um "traco" de referencia por e^{-s} e recomputar S_core (que o ignora)
