    # (5) A PODA GANHA TRACO [REAL no finito] -- setor vivo (populacoes) preservado
    rho = np.diag([0.94, 0.03, 0.02, 0.01]).astype(complex); rho[0, 3] = rho[3, 0] = 0.02
