r'''import Mathlib

set_option autoImplicit false

/-!
Probe de diagnostico (NAO importado pela biblioteca TGL, nao entra em selo).

RESULTADO DA INVESTIGACAO (mathlib v4.31.0):
  - `inner_self_eq_norm_sq_to_K : inner рқ•ң x x = (вҖ–xвҖ– : рқ•ң) ^ 2`  usa `RCLike.ofReal`;
    misturar isso com `Complex.ofReal` no enunciado da a dois ATOMOS distintos e
    `ring`/`rfl` nao fecham. Solucao: ficar em в„қ via `RCLike.re`.
  - `inner_self_eq_norm_sq : RCLike.re (inner рқ•ң x x) = вҖ–xвҖ– ^ 2`  <-- a rota usada.
  - `inner_self_nonneg : 0 вүӨ RCLike.re (inner рқ•ң x x)`.
-/

#check @inner_self_eq_norm_sq_to_K
#check @inner_self_eq_norm_sq
#check @inner_self_nonneg
#check @inner_self_eq_zero

-- a forma SEM coercao (compila)
example (n : в„•) (D : EuclideanSpace в„Ӯ (Fin n) вҶ’вӮ—[в„Ӯ] EuclideanSpace в„Ӯ (Fin n))
    (x : EuclideanSpace в„Ӯ (Fin n)) :
    inner в„Ӯ x (LinearMap.adjoint D (D x)) = inner в„Ӯ (D x) (D x) := by
  rw [LinearMap.adjoint_inner_right]

-- a forma REAL, que evita a coercao в„қвҶ’в„Ӯ (compila)
example (n : в„•) (D : EuclideanSpace в„Ӯ (Fin n) вҶ’вӮ—[в„Ӯ] EuclideanSpace в„Ӯ (Fin n))
    (x : EuclideanSpace в„Ӯ (Fin n)) :
    RCLike.re (inner в„Ӯ (D x) (D x)) = вҖ–D xвҖ– ^ 2 :=
  inner_self_eq_norm_sq (D x)
''',
