r'''import Mathlib

set_option autoImplicit false

/-!
# Probe3 -- descoberta de API para a rigidificacao (FASE B)   [DIAGNOSTICO]

Verifica o que EXISTE na mathlib v4.31.0 antes de escrever a estrutura rigida:
von Neumann algebras, star/adjoint em `H вҶ’L[в„Ӯ] H`, SetLike, Dense+span,
pecas de Minkowski. NAO importado por TGL.lean.
-/

namespace TGL.Probe3

-- (1) VonNeumannAlgebra existe? membership? coercao a Set?
#check @VonNeumannAlgebra
example (H : Type) [NormedAddCommGroup H] [InnerProductSpace в„Ӯ H] [CompleteSpace H]
    (A : VonNeumannAlgebra H) (a : H вҶ’L[в„Ӯ] H) : Prop := a вҲҲ A
example (H : Type) [NormedAddCommGroup H] [InnerProductSpace в„Ӯ H] [CompleteSpace H]
    (A : VonNeumannAlgebra H) : Set (H вҶ’L[в„Ӯ] H) := (A : Set (H вҶ’L[в„Ӯ] H))

-- (2) star (adjunto) em H вҶ’L[в„Ӯ] H
example (H : Type) [NormedAddCommGroup H] [InnerProductSpace в„Ӯ H] [CompleteSpace H]
    (a : H вҶ’L[в„Ӯ] H) : H вҶ’L[в„Ӯ] H := star a

-- (3) mul = composicao; unidade
example (H : Type) [NormedAddCommGroup H] [InnerProductSpace в„Ӯ H] [CompleteSpace H]
    (a b : H вҶ’L[в„Ӯ] H) : H вҶ’L[в„Ӯ] H := a * b
example (H : Type) [NormedAddCommGroup H] [InnerProductSpace в„Ӯ H] [CompleteSpace H] :
    H вҶ’L[в„Ӯ] H := 1

-- (4) Commute em H вҶ’L[в„Ӯ] H
example (H : Type) [NormedAddCommGroup H] [InnerProductSpace в„Ӯ H] [CompleteSpace H]
    (a b : H вҶ’L[в„Ӯ] H) : Prop := Commute a b

-- (5) Dense do span (ciclicidade enunciavel)
example (H : Type) [NormedAddCommGroup H] [InnerProductSpace в„Ӯ H] (s : Set H) : Prop :=
  Dense ((Submodule.span в„Ӯ s : Submodule в„Ӯ H) : Set H)

-- (6) pecas de Minkowski em Fin 4 вҶ’ в„қ
example (v : Fin 4 вҶ’ в„қ) : в„қ := v 0 ^ 2 - v 1 ^ 2 - v 2 ^ 2 - v 3 ^ 2
example (x : Fin 4 вҶ’ в„қ) : Prop := |x 0| < x 1
example (x y : Fin 4 вҶ’ в„қ) : Fin 4 вҶ’ в„қ := x - y
example (v : Fin 4 вҶ’ в„қ) (a : Fin 4 вҶ’ в„қ) : Set (Fin 4 вҶ’ в„қ) вҶ’ Set (Fin 4 вҶ’ в„қ) :=
  fun O => (fun x => x + a) '' O

-- (7) aplicacao de operador a vetor (imagem do vacuo)
example (H : Type) [NormedAddCommGroup H] [InnerProductSpace в„Ӯ H] [CompleteSpace H]
    (a : H вҶ’L[в„Ӯ] H) (v : H) : H := a v

#eval IO.println "PROBE3_OK"

end TGL.Probe3
''',
