    for n in range(1, 13):
        h = 2.0 ** (-n)
        err = max(abs(t - round(t / h) * h) for t in targets_t)
        if dyadic_first is None:
            dyadic_first = err
        dyadic_last = err
        dyadic_ok = dyadic_ok and (err <= h / 2.0 + 1e-15)

    # a obstrucao do traco discreto (o espelho numerico do teorema KERNEL)
    obstruction_ok = True
