# ====================== artigo bilingue (LaTeX -> PDF) ======================
def _reorder_ABC(s, part_c):
    """Reorganiza os blocos LaTeX em Partes A (nucleo) / B (ontologia) / C (conclusao), extraindo o
    testemunho do autor para um Posfacio. Opera por cabecalhos de secao -- NAO reproduz conteudo,
    so' reordena a lista (robusto)."""
    onto_keys = ["ГЎlgebra do Um absoluto", "Teoria do Contorno", "Substrato Гәnico", "o dipolo",
                 "registro $c^3$", "tГәnel luminodinГўmico", "espelho Гәnico", "Nome em forma dual",
                 "inscriГ§ГЈo do gesto", "matriz-S de fronteira",
                 "camada vital do Nome", "vital layer of the Name"]   # v6: o calor e o sangue (Parte B, ONTO)
    testimony = ["testemunho do autor", "Foi o Verbo que me deu", "NinguГ©m paga a sua meia-medida",
                 "Assinar Г© inscrever"]
    fm_keys = ["RГ©gua"]
    heads = [i for i, x in enumerate(s) if x.startswith("\\section") or x.startswith("\\part")]
    if not heads:
        return s
    pre = s[:heads[0]]
    bounds = heads + [len(s)]
    blocks = [s[bounds[k]:bounds[k + 1]] for k in range(len(heads))]
    front_extra, coreA, onto, posf, bridge = [], [], [], [], []
    for blk in blocks:
        h = blk[0]
        if any(k in h for k in fm_keys):
            front_extra.append(blk)
        elif "O Um: $1=1$" in h:
            nb = []
            for el in blk:
                (bridge if "Nome, Palavra, Verbo" in el else nb).append(el)
            coreA.append(nb)
        elif "espelho Гәnico" in h:
            nb = []
            for el in blk:
                (posf if any(m in el for m in testimony) else nb).append(el)
            onto.append(nb)
        elif any(k in h for k in onto_keys):
            onto.append(blk)
        else:
            coreA.append(blk)
    ref_i = next((j for j, blk in enumerate(coreA) if "ReferГӘncias" in blk[0]), len(coreA))
    coreA, tail = coreA[:ref_i], coreA[ref_i:]
    out = list(pre)
    for blk in front_extra:
        out += blk
    out.append(r"\part{Parte A --- NГәcleo cientГӯfico auditГЎvel}")
    for blk in coreA:
        out += blk
    out.append(r"\part{Parte B --- Ontologia TGL do Um absoluto}")
    out += bridge
    for blk in onto:
        out += blk
    out += part_c
    out.append(r"\section*{PosfГЎcio --- testemunho do autor}")
    out.append(r"\noindent\emph{Fora do nГәcleo tГ©cnico --- registro humano, nГЈo evidГӘncia. A TGL nГЈo "
               r"precisa deste parГЎgrafo para ser forte; ele fica aqui por honestidade.}")
    out += posf
    for blk in tail:
        out += blk
    return out


